select from student_sop
and status = #{status}
and mentor_id = #{mentorId}
and exists ( select 1 from student s where s.id = student_sop.student_id and s.student_name like concat('%', #{studentName}, '%') )
and exists ( select 1 from student s where s.id = student_sop.student_id and s.student_phone like concat('%', #{studentPhone}, '%') )
order by id desc
